input.content:
// SvgIcon.ets — 手作·印记 共享图标入口
//
// 保持稳定 API: variant / iconSize / color / strokeWidth。
// 本工程暂无 rawfile SVG 资源，故此处以 ArkUI 矢量几何直接绘制简洁线性图标，
// 避免依赖缺失文件，亦不使用 emoji/象形 Unicode 充当图标。
// 后续若引入 rawfile SVG，可在此处切换为 Image($rawfile(...)) 实现。

@Component
export struct SvgIcon {
  @Prop iconSize: number = 24;
  @Prop color: string = '#3D2E22';
  @Prop strokeWidth: number = 2;
  @Prop variant: string = 'home';

  build() {
    Stack() {
      this.Glyph()
    }
    .width(this.iconSize)
    .height(this.iconSize)
  }

  @Builder
  Glyph() {
    // 24x24 视口，统一线性描边风格
    Shape() {
      this.Paths()
    }
    .width('100%')
    .height('100%')
    .viewPort({ x: 0, y: 0, width: 24, height: 24 })
    .fillOpacity(0)
    .stroke(this.color)
    .strokeWidth(this.strokeWidth)
    .strokeLineCap(LineCapStyle.Round)
    .strokeLineJoin(LineJoinStyle.Round)
  }

  @Builder
  Paths() {
    if (this.variant === 'home') {
      Path().commands('M3 11.5 L12 4 L21 11.5')
      Path().commands('M5 10.5 L5 20 L9.5 20 L9.5 14 L14.5 14 L14.5 20 L19 20 L19 10.5')
    } else if (this.variant === 'classes' || this.variant === 'calendar') {
      Path().commands('M4 7 L4 20 L20 20 L20 7 Z')
      Path().commands('M4 11 L20 11')
      Path().commands('M8 4 L8 9')
      Path().commands('M16 4 L16 9')
    } else if (this.variant === 'points' || this.variant === 'star') {
      Path().commands('M12 3.5 L14.6 9 L20.5 9.7 L16.1 13.8 L17.3 19.6 L12 16.6 L6.7 19.6 L7.9 13.8 L3.5 9.7 L9.4 9 Z')
    } else if (this.variant === 'profile' || this.variant === 'user') {
      Path().commands('M12 12 a4 4 0 1 0 0.01 0') // 头部圆
      Circle({ width: 7, height: 7 }).center({ x: 12, y: 9 })
      Path().commands('M5 20 a7 7 0 0 1 14 0')
    } else if (this.variant === 'back') {
      Path().commands('M15 5 L8 12 L15 19')
    } else if (this.variant === 'plus' || this.variant === 'add') {
      Path().commands('M12 5 L12 19')
      Path().commands('M5 12 L19 12')
    } else if (this.variant === 'minus' || this.variant === 'remove') {
      Path().commands('M5 12 L19 12')
    } else if (this.variant === 'bell' || this.variant === 'dormant') {
      Path().commands('M6 17 L18 17 L17 15 L17 11 a5 5 0 0 0 -10 0 L7 15 Z')
      Path().commands('M10 19 a2 2 0 0 0 4 0')
    } else if (this.variant === 'box' || this.variant === 'inventory') {
      Path().commands('M3.5 7.5 L12 3.5 L20.5 7.5 L20.5 16.5 L12 20.5 L3.5 16.5 Z')
      Path().commands('M3.5 7.5 L12 11.5 L20.5 7.5')
      Path().commands('M12 11.5 L12 20.5')
    } else if (this.variant === 'camera' || this.variant === 'image') {
      Path().commands('M4 8 L7 8 L8.5 5.5 L15.5 5.5 L17 8 L20 8 L20 19 L4 19 Z')
      Circle({ width: 6, height: 6 }).center({ x: 12, y: 13 })
    } else if (this.variant === 'chevronRight' || this.variant === 'arrowRight') {
      Path().commands('M9 5 L16 12 L9 19')
    } else if (this.variant === 'edit') {
      Path().commands('M5 19 L5 15 L15 5 L19 9 L9 19 Z')
      Path().commands('M13 7 L17 11')
    } else if (this.variant === 'check') {
      Path().commands('M5 12.5 L10 17.5 L19 7')
    } else if (this.variant === 'alert') {
      Path().commands('M12 4 L21 19 L3 19 Z')
      Path().commands('M12 10 L12 14')
      Circle({ width: 1.6, height: 1.6 }).center({ x: 12, y: 16.6 })
    } else if (this.variant === 'gift') {
      Path().commands('M4 11 L20 11 L20 20 L4 20 Z')
      Path().commands('M4 8 L20 8')
      Path().commands('M12 8 L12 20')
      Path().commands('M12 8 C9 8 7 7 7 5.5 C7 4.3 9 4 12 8 C15 4 17 4.3 17 5.5 C17 7 15 8 12 8')
    } else if (this.variant === 'clock') {
      Circle({ width: 16, height: 16 }).center({ x: 12, y: 12 })
      Path().commands('M12 7 L12 12 L15.5 14')
    } else if (this.variant === 'settings') {
      Circle({ width: 5, height: 5 }).center({ x: 12, y: 12 })
      Path().commands('M12 3 L12 5.5 M12 18.5 L12 21 M21 12 L18.5 12 M5.5 12 L3 12 M18.4 5.6 L16.6 7.4 M7.4 16.6 L5.6 18.4 M18.4 18.4 L16.6 16.6 M7.4 7.4 L5.6 5.6')
    } else if (this.variant === 'heart' || this.variant === 'favorite') {
      Path().commands('M12 20 C5 15 3 11 3 8 a4 4 0 0 1 8-1 a4 4 0 0 1 8 1 c0 3-2 7-7 12 Z')
    } else if (this.variant === 'trash') {
      Path().commands('M5 7 L19 7 M9 7 L9 5 L15 5 L15 7 M7 7 L8 20 L16 20 L17 7')
    } else if (this.variant === 'search') {
      Circle({ width: 9, height: 9 }).center({ x: 10.5, y: 10.5 })
      Path().commands('M17 17 L21 21')
    } else if (this.variant === 'flame' || this.variant === 'streak') {
      Path().commands('M12 3 C13 7 17 8 17 13 a5 5 0 0 1 -10 0 C7 10 9 9 10 7 C10.5 8.5 11.5 6.5 12 3 Z')
    } else {
      // 默认: 圆点
      Circle({ width: 8, height: 8 }).center({ x: 12, y: 12 })
    }
  }
}

