      });
    }
    for (const c of DataStore.state.consumption) {
      items.push({
        id: c.id, title: c.title,
        subtitle: c.amountPoint > 0 ? `-${c.amountPoint} 积分` : '已记录',
        date: c.date,
      });
    }
    items.sort((a: ActivityItem, b: ActivityItem) => b.date.localeCompare(a.date));
