// ClayButton.ets — 陶土风按钮
import { Theme } from '../common/Theme';

@Component
export struct ClayButton {
  @Prop label: string = '';
  @Prop filled: boolean = true;
  @Prop disabled: boolean = false;
  @Prop compact: boolean = false;
  onClick: () => void = () => {};

  build() {
    Button({ type: ButtonType.Custom, stateEffect: !this.disabled }) {
      Row() {
        Text(this.label)
          .fontSize(this.compact ? 14 : 16)
          .fontWeight(FontWeight.Bold)
          .fontColor(this.filled ? Theme.textOnClay : (this.disabled ? Theme.textQuaternary : Theme.brandDark))
      }
      .width('100%')
      .height(this.compact ? 40 : 50)
      .justifyContent(FlexAlign.Center)
    }
    .width('100%')
    .backgroundColor(this.filled
      ? (this.disabled ? Theme.textQuaternary : Theme.brandPrimary)
      : Theme.chipSoftBg)
    .borderRadius(Theme.radiusButton)
    .opacity(this.disabled ? 0.6 : 1.0)
    .enabled(!this.disabled)
    .onClick(() => {
      if (!this.disabled) {
        this.onClick();
      }
    })
  }
}

