// HomePage.ets — 首页: 签到 / 积分余额 / 连续天数 / 最近动态 / 沉睡提醒入口
import { Theme, BrandGradient } from '../common/Theme';
import { TabId } from '../common/TabTypes';
import { SvgIcon } from '../common/SvgIcon';
import { ClayCard } from '../components/ClayCard';
import { EmptyState } from '../components/EmptyState';
import { DataStore } from '../services/DataStore';
import { DateUtil } from '../services/DateUtil';
import { ActivityItem } from '../model/Models';

@Component
export struct HomePage {
  @Prop refreshTick: number = 0;
  goToTab: (tab: TabId) => void = () => {};
  goDormant: () => void = () => {};

  @State name: string = '';
  @State balance: number = 0;
  @State streak: number = 0;
  @State lastCheckIn: string = '';
  @State activities: ActivityItem[] = [];
  @State dormantCount: number = 0;
  @State feedback: string = '';
  @Watch('refreshTick') @Prop watchTick: number = 0;

  aboutToAppear(): void {
    this.load();
  }

  private load(): void {
    const m = DataStore.getCurrentMember();
    this.name = m.name.length > 0 ? m.name : '手作之友';
    this.balance = DataStore.getBalance();
    this.streak = DataStore.getStreak();
    this.lastCheckIn = DataStore.getLastCheckIn();
    this.activities = DataStore.getActivities();
    this.dormantCount = DataStore.getDormantMembers().length;
  }

  private get checkedToday(): boolean {
    return this.lastCheckIn === DateUtil.todayStr();
  }

  private doCheckIn(): void {
    const r = DataStore.checkIn();
    this.feedback = r.message;
    this.load();
    setTimeout(() => { this.feedback = ''; }, 2600);
  }

  build() {
    Column() {
      // 标题区
      Row() {
        Column() {
          Text('手作·印记')
            .fontSize(Theme.fontDisplay)
            .fontWeight(FontWeight.Bold)
            .fontColor(Theme.brandDark)
          Text(this.greeting())
            .fontSize(13)
            .fontColor(Theme.textSecondary)
            .margin({ top: 2 })
        }
        .alignItems(HorizontalAlign.Start)
        Blank()
        Row() {
          SvgIcon({ variant: 'flame', iconSize: 18, color: Theme.ochre })
          Text(`${this.streak} 天`)
            .fontSize(13)
            .fontWeight(FontWeight.Bold)
            .fontColor(Theme.brandDark)
            .margin({ left: 4 })
        }
        .padding({ left: 12, right: 12, top: 6, bottom: 6 })
        .backgroundColor(Theme.cardBg)
        .borderRadius(Theme.radiusPill)
        .border({ width: 1, color: Theme.borderDefault })
      }
      .width('100%')
      .padding({ left: 16, right: 16, top: 16, bottom: 8 })
      .alignItems(VerticalAlign.Center)

      Scroll() {
        Column() {
          // 积分余额卡 + 签到
          ClayCard({ paddingV: 20 }) {
            Column() {
              Row() {
                Text('积分余额')
                  .fontSize(13)
                  .fontColor(Theme.textSecondary)
                Blank()
                Text(`累计 ${DataStore.getLifetime()}`)
                  .fontSize(12)
                  .fontColor(Theme.textTertiary)
              }
              .width('100%')
              Text(`${this.balance}`)
                .fontSize(46)
                .fontWeight(FontWeight.Bold)
                .fontColor(Theme.brandDark)
                .margin({ top: 6, bottom: 14 })

              if (this.feedback.length > 0) {
                Text(this.feedback)
                  .fontSize(13)
                  .fontColor(this.checkedToday ? Theme.warningText : Theme.successText)
                  .margin({ bottom: 10 })
              }

              Button(this.checkedToday ? '今日已签到' : '签到 +积分') {
                Row() {
                  if (!this.checkedToday) {
                    SvgIcon({ variant: 'check', iconSize: 18, color: Theme.textOnClay })
                  }
                  Text(this.checkedToday ? '今日已签到' : '立即签到')
                    .fontSize(16)
                    .fontWeight(FontWeight.Bold)
                    .fontColor(Theme.textOnClay)
                    .margin({ left: this.checkedToday ? 0 : 6 })
                }
                .height(50)
                .justifyContent(FlexAlign.Center)
              }
              .width('100%')
              .backgroundColor(this.checkedToday ? Theme.textQuaternary : Theme.brandPrimary)
              .borderRadius(Theme.radiusButton)
              .enabled(!this.checkedToday)
              .onClick(() => this.doCheckIn())
            }
          }
          .margin({ left: 16, right: 16, top: 8 })

          // 沉睡会员提醒(店主入口)
          if (this.dormantCount > 0) {
            Row() {
              SvgIcon({ variant: 'bell', iconSize: 20, color: Theme.warningText })
              Column() {
                Text(`${this.dormantCount} 位会员沉睡中`)
                  .fontSize(14)
                  .fontWeight(FontWeight.Bold)
                  .fontColor(Theme.warningText)
                Text('点此查看并发送唤醒权益')
                  .fontSize(12)
                  .fontColor(Theme.textSecondary)
              }
              .margin({ left: 10 })
              .alignItems(HorizontalAlign.Start)
              Blank()
              SvgIcon({ variant: 'chevronRight', iconSize: 18, color: Theme.warningText })
            }
            .width('100%')
            .padding(14)
            .backgroundColor(Theme.warningBg)
            .borderRadius(Theme.radiusCard)
            .border({ width: 1, color: '#EAD0A6' })
            .margin({ left: 16, right: 16, top: 12 })
            .onClick(() => this.goDormant())
          }

          // 最近动态
          Row() {
            Text('最近动态')
              .fontSize(Theme.fontTitle)
              .fontWeight(FontWeight.Bold)
              .fontColor(Theme.textPrimary)
            Blank()
            if (this.activities.length > 0) {
              Text('查看积分')
                .fontSize(13)
                .fontColor(Theme.brandPrimary)
                .onClick(() => this.goToTab('tab-points'))
            }
          }
          .width('100%')
          .padding({ left: 16, right: 16, top: 20, bottom: 8 })

          if (this.activities.length === 0) {
            ClayCard({ paddingV: 8 }) {
              EmptyState({
                icon: 'clock',
                title: '还没有动态',
                hint: '签到或预约课程后，这里会记录你的手作足迹'
              })
            }
            .margin({ left: 16, right: 16 })
          } else {
            Column() {
              ForEach(this.activities.slice(0, 6), (a: ActivityItem) => {
                Row() {
                  Column() {
                    Text(a.title)
                      .fontSize(14)
                      .fontWeight(FontWeight.Medium)
                      .fontColor(Theme.textPrimary)
                      .maxLines(1)
                      .textOverflow({ overflow: TextOverflow.Ellipsis })
                    Text(`${DateUtil.shortDate(a.date)} · ${DateUtil.weekdayLabel(a.date)}`)
                      .fontSize(12)
                      .fontColor(Theme.textTertiary)
                      .margin({ top: 2 })
                  }
                  .alignItems(HorizontalAlign.Start)
                  .layoutWeight(1)
                  Text(a.subtitle)
                    .fontSize(13)
                    .fontWeight(FontWeight.Bold)
                    .fontColor(a.subtitle.startsWith('+') ? Theme.successText : Theme.textSecondary)
                }
                .width('100%')
                .padding({ top: 12, bottom: 12 })
                .border({ width: { bottom: 1 }, color: { bottom: Theme.cardDivider } })
                .id(`home-activity-${a.id}`)
              }, (a: ActivityItem) => a.id)
            }
            .width('100%')
            .padding({ left: 16, right: 16 })
            .backgroundColor(Theme.cardBg)
            .borderRadius(Theme.radiusCard)
            .border({ width: 1, color: Theme.borderSoft })
            .margin({ left: 16, right: 16 })
          }
          Blank().height(8)
        }
      }
      .layoutWeight(1)
      .scrollBar(BarState.Off)
      .align(Alignment.Top)
    }
    .width('100%')
    .height('100%')
  }

  private greeting(): string {
    const h = new Date().getHours();
    if (h < 6) return '夜深了，记得早些休息';
    if (h < 12) return '早安，今天也要感受泥土的温度';
    if (h < 18) return '午后好，约一节课放松下吧';
    return '晚上好，记录今天的手作印记';
  }
}

