// ClassesPage.ets — 课程预约: 周日历 + 课程列表 + 预约/取消 + 库存预警
import { Theme } from '../common/Theme';
import { TabId } from '../common/TabTypes';
import { SvgIcon } from '../common/SvgIcon';
import { ClayCard } from '../components/ClayCard';
import { EmptyState } from '../components/EmptyState';
import { DataStore } from '../services/DataStore';
import { DateUtil } from '../services/DateUtil';
import { ClassSlot, OpResult } from '../model/Models';

@Component
export struct ClassesPage {
  @Prop @Watch('onRefreshTick') refreshTick: number = 0;
  goToTab: (tab: TabId) => void = () => {};
  openDetail: (classId: string) => void = () => {};

  @State week: string[] = [];
  @State selectedDate: string = '';
  @State slots: ClassSlot[] = [];
  @State feedback: string = '';

  aboutToAppear(): void {
    this.week = DateUtil.currentWeek();
    this.selectedDate = DateUtil.todayStr();
    this.loadSlots();
  }

  onRefreshTick(): void {
    this.loadSlots();
  }

  private loadSlots(): void {
    const all = DataStore.getClasses();
    this.slots = all.filter((c: ClassSlot) => c.date === this.selectedDate);
  }

  private onSelectDate(d: string): void {
    this.selectedDate = d;
    this.loadSlots();
  }

  private stockWarnText(slot: ClassSlot): string {
    for (const mat of slot.materials) {
      const inv = DataStore.getInventory().find((i) => i.id === mat.inventoryItemId);
      if (!inv || inv.quantity < mat.quantityPerSeat) {
        return `耗材「${inv ? inv.name : mat.name}」不足`;
      }
    }
    return '';
  }

  private canBook(slot: ClassSlot): boolean {
    if (slot.booked >= slot.capacity) {
      return false;
    }
    return this.stockWarnText(slot).length === 0;
  }

  private book(slot: ClassSlot): void {
    const r: OpResult = DataStore.bookSlot(slot.id);
    this.feedback = r.message;
    this.loadSlots();
    setTimeout(() => { this.feedback = ''; }, 2600);
  }

  private cancel(slot: ClassSlot): void {
    const r: OpResult = DataStore.cancelSlot(slot.id);
    this.feedback = r.message;
    this.loadSlots();
    setTimeout(() => { this.feedback = ''; }, 2600);
  }

  build() {
    Column() {
      // 标题
      Row() {
        Text('课程预约')
          .fontSize(Theme.fontTitle)
          .fontWeight(FontWeight.Bold)
          .fontColor(Theme.textPrimary)
        Blank()
        SvgIcon({ variant: 'calendar', iconSize: 20, color: Theme.brandPrimary })
      }
      .width('100%')
      .padding({ left: 16, right: 16, top: 16, bottom: 8 })

      // 周日历
      Row() {
        ForEach(this.week, (d: string) => {
          Column() {
            Text(DateUtil.weekdayLabel(d).replace('周', ''))
              .fontSize(12)
              .fontColor(this.selectedDate === d ? Theme.textOnClay : Theme.textTertiary)
            Text(DateUtil.parseStr(d).getDate().toString())
              .fontSize(17)
              .fontWeight(FontWeight.Bold)
              .fontColor(this.selectedDate === d ? Theme.textOnClay : Theme.textPrimary)
              .margin({ top: 2 })
          }
          .justifyContent(FlexAlign.Center)
          .width(42)
          .height(58)
          .backgroundColor(this.selectedDate === d ? Theme.brandPrimary : Theme.cardBg)
          .borderRadius(Theme.radiusSmall)
          .border({ width: 1, color: this.selectedDate === d ? Theme.brandPrimary : Theme.borderSoft })
          .margin({ left: 2, right: 2 })
          .onClick(() => this.onSelectDate(d))
        }, (d: string) => d)
      }
      .width('100%')
      .padding({ left: 12, right: 12, bottom: 8 })

      if (this.feedback.length > 0) {
        Text(this.feedback)
          .fontSize(13)
          .fontColor(Theme.successText)
          .padding({ left: 16, right: 16, bottom: 4 })
      }

      // 课程列表
      Scroll() {
        Column() {
          if (this.slots.length === 0) {
            ClayCard({ paddingV: 8 }) {
              EmptyState({
                icon: 'calendar',
                title: '这天暂无课程',
                hint: '换个日期看看其他手作体验吧'
              })
            }
            .margin({ left: 16, right: 16, top: 8 })
          } else {
            ForEach(this.slots, (slot: ClassSlot) => {
              this.SlotCard(slot)
            }, (slot: ClassSlot) => slot.id)
          }
          Blank().height(12)
        }
      }
      .layoutWeight(1)
      .scrollBar(BarState.Off)
      .align(Alignment.Top)
    }
    .width('100%')
    .height('100%')
  }

  @Builder
  SlotCard(slot: ClassSlot) {
    Column() {
      Row() {
        Column() {
          Text(slot.title)
            .fontSize(17)
            .fontWeight(FontWeight.Bold)
            .fontColor(Theme.textPrimary)
          Row() {
            SvgIcon({ variant: 'clock', iconSize: 14, color: Theme.textTertiary })
            Text(`${DateUtil.weekdayLabel(slot.date)} ${slot.time}`)
              .fontSize(12)
              .fontColor(Theme.textTertiary)
              .margin({ left: 4 })
          }
          .margin({ top: 4 })
        }
        .alignItems(HorizontalAlign.Start)
        .layoutWeight(1)
        Text(`${slot.booked}/${slot.capacity}`)
          .fontSize(13)
          .fontWeight(FontWeight.Bold)
          .fontColor(slot.booked >= slot.capacity ? Theme.dangerText : Theme.brandDark)
      }
      .width('100%')

      Text(slot.description)
        .fontSize(13)
        .fontColor(Theme.textSecondary)
        .margin({ top: 8 })
