// PointsPage.ets — 积分与消费: 余额 / 累计 / 明细分段(积分 / 消费)
import { Theme } from '../common/Theme';
import { SvgIcon } from '../common/SvgIcon';
import { ClayCard } from '../components/ClayCard';
import { EmptyState } from '../components/EmptyState';
import { DataStore } from '../services/DataStore';
import { DateUtil } from '../services/DateUtil';
import { PointRecord, ConsumptionRecord } from '../model/Models';

@Component
export struct PointsPage {
  @Prop @Watch('onRefreshTick') refreshTick: number = 0;
  @State segment: number = 0; // 0 积分明细, 1 消费记录
  @State balance: number = 0;
  @State lifetime: number = 0;
  @State points: PointRecord[] = [];
  @State consumption: ConsumptionRecord[] = [];

  aboutToAppear(): void {
    this.load();
  }

  onRefreshTick(): void {
    this.load();
  }

  private load(): void {
    this.balance = DataStore.getBalance();
    this.lifetime = DataStore.getLifetime();
    this.points = DataStore.getPointRecords();
    this.consumption = DataStore.getConsumption();
  }

  build() {
    Column() {
      Text('积分与消费')
        .fontSize(Theme.fontTitle)
        .fontWeight(FontWeight.Bold)
        .fontColor(Theme.textPrimary)
        .width('100%')
        .padding({ left: 16, right: 16, top: 16, bottom: 8 })

      // 余额卡
      ClayCard({ paddingV: 20 }) {
        Column() {
          Row() {
            Text('当前积分')
              .fontSize(13)
              .fontColor(Theme.textSecondary)
            Blank()
            Row() {
              SvgIcon({ variant: 'star', iconSize: 16, color: Theme.ochre })
              Text(`累计获得 ${this.lifetime}`)
                .fontSize(12)
                .fontColor(Theme.textTertiary)
                .margin({ left: 4 })
            }
          }
          .width('100%')
          Text(`${this.balance}`)
            .fontSize(44)
            .fontWeight(FontWeight.Bold)
            .fontColor(Theme.brandDark)
            .margin({ top: 6 })
        }
      }
      .margin({ left: 16, right: 16 })

      // 分段
      Row() {
        Text('积分明细')
          .fontSize(14)
          .fontWeight(FontWeight.Bold)
          .fontColor(this.segment === 0 ? Theme.textOnClay : Theme.textSecondary)
          .layoutWeight(1)
          .textAlign(TextAlign.Center)
          .height(40)
          .backgroundColor(this.segment === 0 ? Theme.brandPrimary : Theme.chipSoftBg)
          .borderRadius(Theme.radiusPill)
          .onClick(() => this.segment = 0)
        Text('消费记录')
          .fontSize(14)
          .fontWeight(FontWeight.Bold)
          .fontColor(this.segment === 1 ? Theme.textOnClay : Theme.textSecondary)
          .layoutWeight(1)
          .textAlign(TextAlign.Center)
          .height(40)
          .backgroundColor(this.segment === 1 ? Theme.brandPrimary : Theme.chipSoftBg)
          .borderRadius(Theme.radiusPill)
          .margin({ left: 8 })
          .onClick(() => this.segment = 1)
      }
      .width('100%')
      .padding({ left: 16, right: 16, top: 14 })
      .id('points-segment')

      // 列表
      Scroll() {
        Column() {
          if (this.segment === 0) {
            if (this.points.length === 0) {
              ClayCard({ paddingV: 8 }) {
                EmptyState({ icon: 'star', title: '还没有积分明细', hint: '签到或预约课程即可获得积分' })
              }
              .margin({ left: 16, right: 16, top: 10 })
            } else {
              Column() {
                ForEach(this.points, (p: PointRecord) => {
                  Row() {
                    Column() {
                      Text(p.reason)
                        .fontSize(14)
                        .fontWeight(FontWeight.Medium)
                        .fontColor(Theme.textPrimary)
                        .maxLines(1)
                        .textOverflow({ overflow: TextOverflow.Ellipsis })
                      Text(DateUtil.shortDate(p.date))
                        .fontSize(12)
                        .fontColor(Theme.textTertiary)
                        .margin({ top: 2 })
                    }
                    .alignItems(HorizontalAlign.Start)
                    .layoutWeight(1)
                    Text(`${p.amount >= 0 ? '+' : ''}${p.amount}`)
                      .fontSize(16)
                      .fontWeight(FontWeight.Bold)
                      .fontColor(p.amount >= 0 ? Theme.successText : Theme.dangerText)
                  }
                  .width('100%')
                  .padding({ top: 12, bottom: 12 })
                  .border({ width: { bottom: 1 }, color: { bottom: Theme.cardDivider } })
                  .id(`points-history-${p.id}`)
                }, (p: PointRecord) => p.id)
              }
              .width('100%')
              .padding({ left: 16, right: 16 })
              .backgroundColor(Theme.cardBg)
              .borderRadius(Theme.radiusCard)
              .border({ width: 1, color: Theme.borderSoft })
              .margin({ left: 16, right: 16, top: 10 })
              .id('points-history-list')
            }
          } else {
            if (this.consumption.length === 0) {
              ClayCard({ paddingV: 8 }) {
                EmptyState({ icon: 'box', title: '还没有消费记录', hint: '预约课程后这里会留痕' })
              }
              .margin({ left: 16, right: 16, top: 10 })
            } else {
              Column() {
                ForEach(this.consumption, (c: ConsumptionRecord) => {
                  Row() {
                    Column() {
                      Text(c.title)
                        .fontSize(14)
                        .fontWeight(FontWeight.Medium)
                        .fontColor(Theme.textPrimary)
                        .maxLines(1)
                        .textOverflow({ overflow: TextOverflow.Ellipsis })
                      Text(DateUtil.shortDate(c.date))
                        .fontSize(12)
                        .fontColor(Theme.textTertiary)
                        .margin({ top: 2 })
                    }
                    .alignItems(HorizontalAlign.Start)
                    .layoutWeight(1)
                    Text(c.amountPoint > 0 ? `-${c.amountPoint} 积分` : '已记录')
                      .fontSize(13)
                      .fontWeight(FontWeight.Bold)
                      .fontColor(c.amountPoint > 0 ? Theme.dangerText : Theme.textSecondary)
                  }
                  .width('100%')
                  .padding({ top: 12, bottom: 12 })
                  .border({ width: { bottom: 1 }, color: { bottom: Theme.cardDivider } })
                  .id(`points-consumption-${c.id}`)
                }, (c: ConsumptionRecord) => c.id)
              }
              .width('100%')
              .padding({ left: 16, right: 16 })
              .backgroundColor(Theme.cardBg)
              .borderRadius(Theme.radiusCard)
              .border({ width: 1, color: Theme.borderSoft })
              .margin({ left: 16, right: 16, top: 10 })
              .id('points-consumption-list')
            }
          }
          Blank().height(12)
        }
      }
      .layoutWeight(1)
      .scrollBar(BarState.Off)
      .align(Alignment.Top)
    }
    .width('100%')
    .height('100%')
  }
}

